// Reading Room newsletter — send one essay to the Resend audience as a branded broadcast.
//
//   node send-newsletter.js <edition>          → creates a DRAFT broadcast (review + send in Resend)
//   node send-newsletter.js <edition> --send   → creates AND sends immediately
//
// Reads the full essay content from feed.xml (already generated by build-essays.py),
// wraps it in the branded email template, and uses the Resend Broadcasts API, which
// handles the audience + unsubscribe automatically. Draft-by-default so a real list
// is never blasted by accident — glance at it in Resend, then hit send.
//
// Env: RESEND_API_KEY, RESEND_AUDIENCE_ID (required). Optional: RESEND_FROM, RESEND_REPLY_TO.
// Requires a verified sending domain in Resend (see 04_business-ops/infrastructure/email-domain.md).

const fs = require('fs');
const path = require('path');

const edition = process.argv[2];
const doSend = process.argv.includes('--send');
if (!edition) {
  console.error('Usage: node send-newsletter.js <edition> [--send]   e.g. node send-newsletter.js 06');
  process.exit(1);
}

const KEY = process.env.RESEND_API_KEY;
const AUD = process.env.RESEND_AUDIENCE_ID;
const FROM = process.env.RESEND_FROM || 'Substrate — Jayden Forshee <jayden@jaydenforshee.com>';
const REPLY = process.env.RESEND_REPLY_TO || 'jayden@jaydenforshee.com';
if (!KEY || !AUD) {
  console.error('Set RESEND_API_KEY and RESEND_AUDIENCE_ID in your environment first.');
  process.exit(1);
}

// --- pull the essay out of feed.xml ---
const feed = fs.readFileSync(path.join(__dirname, 'feed.xml'), 'utf8');
const items = feed.split('<item>').slice(1).map(s => '<item>' + s.split('</item>')[0]);
const item = items.find(it => ((it.match(/<link>([^<]+)<\/link>/) || [])[1] || '').includes('/essays/' + edition + '-'));
if (!item) { console.error('No essay in feed.xml for edition ' + edition + '. Did you run build-essays.py?'); process.exit(1); }

const title = (item.match(/<title>([^<]+)<\/title>/) || [])[1] || 'Substrate — Reading Room';
const link = (item.match(/<link>([^<]+)<\/link>/) || [])[1] || 'https://www.jaydenforshee.com';
const body = (item.match(/<content:encoded><!\[CDATA\[([\s\S]*?)\]\]><\/content:encoded>/) || [])[1] || '';
if (!body) { console.error('No content found for edition ' + edition + '.'); process.exit(1); }

// --- branded email wrapper (mirrors 09_marketing/brand/email-template.html; email-safe) ---
const html = `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#faf8f4;margin:0;padding:0;">
<tr><td align="center" style="padding:36px 16px;">
<table role="presentation" width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#faf8f4;">
<tr><td style="padding:0 0 18px;font-family:'Courier New',Courier,monospace;font-size:11px;letter-spacing:3px;text-transform:uppercase;">
<span style="color:#8b3a1f;">Substrate</span><span style="color:#6e685e;">&nbsp;&middot;&nbsp;The Reading Room</span></td></tr>
<tr><td style="border-top:2px solid #8b3a1f;font-size:0;line-height:0;height:0;">&nbsp;</td></tr>
<tr><td style="padding:30px 0 0;font-family:Georgia,'Times New Roman',serif;font-size:18px;line-height:1.66;color:#3a3631;">
${body}
</td></tr>
<tr><td style="padding:34px 0 0;border-top:1px solid #d4cfc3;">
<p style="font-family:Georgia,serif;font-size:15px;color:#3a3631;margin:20px 0 0;"><a href="${link}" style="color:#8b3a1f;text-decoration:none;">Read this on the site &rarr;</a></p>
<p style="font-family:Georgia,'Times New Roman',serif;font-style:italic;font-size:14px;color:#6e685e;margin:14px 0 0;">Substrate — the practice of Jayden Forshee</p>
<p style="font-family:'Helvetica Neue',Helvetica,Arial,sans-serif;font-size:12px;color:#6e685e;margin:8px 0 0;">
<a href="https://www.jaydenforshee.com" style="color:#8b3a1f;text-decoration:none;">jaydenforshee.com</a>&nbsp;&middot;&nbsp;
<a href="{{{RESEND_UNSUBSCRIBE_URL}}}" style="color:#6e685e;text-decoration:underline;">unsubscribe</a></p>
</td></tr>
</table></td></tr></table>`;

(async () => {
  const create = await fetch('https://api.resend.com/broadcasts', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ audience_id: AUD, from: FROM, reply_to: REPLY, subject: title, html })
  });
  const cj = await create.json().catch(() => ({}));
  if (!create.ok) { console.error('Create broadcast failed:', create.status, cj); process.exit(1); }
  const id = cj.id || (cj.data && cj.data.id);
  console.log('Draft broadcast created:', title, '\n  id:', id);

  if (!doSend) {
    console.log('\nReview it at https://resend.com/broadcasts and click Send there,');
    console.log('or re-run with --send to send now:  node send-newsletter.js ' + edition + ' --send');
    return;
  }

  const send = await fetch(`https://api.resend.com/broadcasts/${id}/send`, {
    method: 'POST', headers: { 'Authorization': `Bearer ${KEY}`, 'Content-Type': 'application/json' }, body: '{}'
  });
  const sj = await send.json().catch(() => ({}));
  if (!send.ok) { console.error('Send failed:', send.status, sj); process.exit(1); }
  console.log('\nSent to the Reading Room audience.');
})();
